// Tom's preferences
var utility = function(state) {
  return state === "pizza" ? 10 : 0;
};

// Transition function: what state results from taking action in state
var transition = function(state, action) {
  if (action === "italian") {
    return "pizza";
  } else {
    return "salad";
  }
};

// The agent picks the action that maximizes utility
var actions = ["italian", "french"];

var maxAgent = function(state) {
  return argMax(function(action) {
    return utility(transition(state, action));
  }, actions);
};

print("Tom's choice: " + maxAgent("initialState"));

var inferenceAgent = function(state) {
  return Infer({method: 'enumerate'}, function() {
    var action = uniformDraw(actions);
    condition(transition(state, action) === 'pizza');
    return action;
  });
};

viz(inferenceAgent('initialState'));

///fold: argMax, expectation
var argMax = function(f, ar){
  return maxWith(f, ar)[0]
};
///

// Choose to eat at the Italian or French restaurants
var actions = ['italian', 'french'];

var transition = function(state, action) {
  if (action === 'italian') {
    return categorical({vs: ['bad', 'good', 'spectacular'], 
                        ps: [0.2, 0.6, 0.2]});
  } else {
    return categorical({vs: ['bad', 'good', 'spectacular'], 
                        ps: [0.05, 0.5, 0.45]});
  }
};

var utility = function(state) {
  if (state === 'bad') {
    return -10;
  } else if (state === 'good') {
    return 6;
  } else {
    return 8;
  }
};

var maxEUAgent = function(state) {
  return argMax(
    function(action) {
      return expectation(Infer({ model() {
        return utility(transition(state, action));
      }}));
    },
    actions);
};

print('Choice in initial state: ' + maxEUAgent('initialState'));

var actions = ['italian', 'french'];

var transition = function(state, action) {
  var nextStates = ['bad', 'good', 'spectacular'];
  var nextProbs = (action === 'italian') ? [0.2, 0.6, 0.2] : [0.05, 0.9, 0.05];
  return categorical(nextProbs, nextStates);
};

var utility = function(state) {
  var table = { 
    bad: -10, 
    good: 6, 
    spectacular: 8 
  };
  return table[state];
};

var softMaxAgent = function(state) {
  return Infer({ 
    model() {
      var action = uniformDraw(actions);
      var expectedUtility = expectation(Infer({ 
        model() {
          return utility(transition(state, action));
        }
      }));
      factor(expectedUtility);
      return action;
    }
  });
};

viz(softMaxAgent('initialState'));

var objects = ['blue square', 'blue circle', 'green square'];
var utterances = ['blue', 'green', 'square', 'circle'];

var meaning = function(utterance, obj) {
  _.includes(obj, utterance);
};

var listener = function(utterance) {
  return Infer({
    model() {
      var obj = uniformDraw(objects);
      var speaker = function(obj) {
        return Infer({
          model() {
            var utterance = uniformDraw(utterances);
            factor(meaning(utterance, obj) ? 0 : -Infinity);
            return utterance;
          }
        });
      };
      factor(speaker(obj).score(utterance));
      return obj;
    }
  });
};

viz(listener('blue'));

