// Here are the building blocks of the Rational Speech Act model

// Possible states of the world
var states = ['blue square', 'blue circle', 'green square'];

// Possible utterances
var utterances = ['blue', 'green', 'square', 'circle'];

// Prior probability of each state
var statePrior = function() {
  return uniformDraw(states);
};

// Prior probability of each utterance
var utterancePrior = function() {
  return uniformDraw(utterances);
};

// Meaning function: does utterance u apply to state s?
var meaning = function(utterance, state) {
  return state.split(' ').includes(utterance);
};

// Literal listener: interprets utterances literally
var literalListener = function(utterance) {
  return Infer({
    model() {
      var state = statePrior();
      condition(meaning(utterance, state));
      return state;
    }
  });
};

viz(literalListener('blue'));
