var k = 1 // number of people who support candidate A
var n = 20 // number of people asked

var model = function() {
  var p = uniform(0, 1); // prior on proportion

  // Observed k people out of n said they support candidate A
  observe(Binomial({p: p, n: n}), k);

  var prior = uniform(0, 1); // prior predictive

  var posteriorPredictive = binomial(p, n); // posterior predictive

  return {
    prior: prior,
    priorPredictive: binomial(prior, n),
    posterior: p,
    posteriorPredictive: posteriorPredictive
  };
}

var opts = {method: "MCMC", callbacks: [editor.MCMCProgress()],
            samples: 2500, burn: 250}

var posterior = Infer(opts, model);

viz.marginals(posterior);

