var n = 20  // number of people asked

var model = function() {

   // true population proportion who support candidate A
   var p = uniform(0, 1);

   // Observed k people support "A"
   // Assuming each person's response is independent of each other
   observe(Binomial({p : p, n: n}), k);

   return p
}

var posterior = Infer(model);

// Compute 90% credible interval
var credibleInterval = function(dist, percentile) {
  var samples = repeat(10000, function() { return sample(dist); });
  var sorted = sort(samples);
  var low = sorted[Math.floor((1 - percentile) / 2 * samples.length)];
  var high = sorted[Math.floor((1 - (1 - percentile) / 2) * samples.length)];
  return [low, high];
}

print("90% credible interval: " + credibleInterval(posterior, 0.9))

