var residuals = function(probs) {
  if (probs.length === 0) {
    return [];
  } else {
    var p = probs[0];
    var rest = probs.slice(1);
    var restSum = rest.reduce(function(a, b) { return a + b; }, 0);
    var residual = restSum === 0 ? 1 : p / (p + restSum);
    return [residual].concat(residuals(rest));
  }
};

