[block_11]
Looking at the document, BLOCK_11 is in the section "Example: Goldwater Model 1" which is adapted from Goldwater 2009. This is a word segmentation model using the Dirichlet Process. The Goldwater Model 1 uses a CRP/DP to segment words from a continuous stream of phonemes.

```block_11
// Goldwater Model 1: Unsupervised word segmentation
// Adapted from Goldwater (2009)

// The model assumes that utterances are generated by sampling words
// from a lexicon, where the lexicon itself is generated by a DP.
// The base distribution generates words by sampling phonemes.

var pickStick = function(sticks, J) {
  return flip(sticks(J)) ? J : pickStick(sticks, J+1);
};

var makeSticks = function(alpha) {
  var sticks = mem(function(index) { return beta(1, alpha) });
  return function() {
    return pickStick(sticks, 1);
  };
};

var DPmem = function(alpha, baseDist) {
  var augmentedProc = mem(function(args, stickIndex) { return apply(baseDist, args) });
  var DP = mem(function(args) { return makeSticks(alpha) });
  return function(argsin) {
    var stickIndex = DP(argsin)();
    return augmentedProc(argsin, stickIndex);
  };
};

// phoneme inventory
var phonemes = ['a', 'b', 'd', 'i', 'l', 'n', 'r', 's', 't', 'u'];

// base distribution: sample a word by sampling a random number of phonemes
var sampleWord = function() {
  var len = randomInteger(4) + 1; // word length between 1 and 4
  return repeat(len, function() { return phonemes[randomInteger(phonemes.length)] }).join('');
};

// DP memoized word generator: creates a lexicon
var alpha = 1;
var getWord = DPmem(alpha, sampleWord);

// sample some words from the lexicon
var lexiconSample = repeat(20, function() { return getWord() });
print("Sample words from DP lexicon:");
print(lexiconSample);

// Show that words get reused (rich-get-richer)
var wordCounts = _.countBy(repeat(100, function() { return getWord() }), _.identity);
print("Word frequency distribution (showing reuse):");
print(wordCounts);
```

