// Expected utility function
var expectedUtility = function(state, action, timeLeft) {
  var u = utility(state, action);
  if (timeLeft === 1) {
    return u;
  } else {
    return u + expectation(Infer({ method: 'enumerate' }, function() {
      var nextState = transition(state, action);
      var nextAction = sample(act(nextState, timeLeft - 1));
      return expectedUtility(nextState, nextAction, timeLeft - 1);
    }));
  }
};

// Transition function
