// Construct a POMDP agent

var makePOMDPAgent = function(params, world) {
  var utility = params.utility;
  var alpha = params.alpha;

  var transition = world.transition;
  var observe = world.observe;
  var stateToActions = world.stateToActions;

  // belief update: given current belief b, action a, and observation o,
  // return the new belief b'
  var updateBelief = dp.cache(
    function(belief, action, observation) {
      return Infer({ model() {
        var state = sample(belief);
        var nextState = transition(state, action);
        var nextObservation = observe(nextState, action);
        condition(_.isEqual(nextObservation, observation));
        return nextState;
      }});
    });

  var act = dp.cache(
    function(belief) {
      return Infer({ model() {
        var state = sample(belief);
        var action = uniformDraw(stateToActions(state));
        var eu = expectedUtility(belief, action);
        factor(alpha * eu);
        return action;
      }});
    });

  var expectedUtility = dp.cache(
    function(belief, action) {
      return expectation(Infer({ model() {
        var state = sample(belief);
        var u = utility(state, action);
        if (state.manifestState.terminateAfterAction) {
          return u;
        } else {
          var nextState = transition(state, action);
          var nextObservation = observe(nextState, action);
          var nextBelief = updateBelief(belief, action, nextObservation);
          var nextAction = sample(act(nextBelief));
          return u + expectedUtility(nextBelief, nextAction);
        }
      }}));
    });

  return { params, act, expectedUtility, updateBelief };
};
