          var strength = mem(function(person){
            return gaussian(0, 1)
          })
          var lazy = function(person){
            return flip(lazinessPrior)
          }
          var pulling = function(person) {
            return lazy(person) ?
                    strength(person) * lazyPulling :
                    strength(person)
          }
          var totalPulling = function(team){ return sum(map(pulling, team)) }
          var winner = function(team1, team2){
            totalPulling(team1) > totalPulling(team2) ? team1 : team2
          }
          var beat = function(team1, team2){ winner(team1, team2) == team1 }

          var matchInfo = itemData[0]

          condition(beat(matchInfo.winner1, matchInfo.loser1))
          if (matchInfo.nWins > 1) { condition(beat(matchInfo.winner2, matchInfo.loser2)) }
          if (matchInfo.nWins > 2) { condition(beat(matchInfo.winner3, matchInfo.loser3)) }

          return strength(matchInfo.target)
        }))

        map(function(d){
