// Recall the Tug-of-war model
var tugOfWarModel = function(lazyPulling, lazinessPrior) {
  var strength = mem(function(person){
    return sample(Gaussian({mu: 0, sigma: 1}))
  })

  var lazy = function(person){
    return flip(lazinessPrior)
  }

  var pulling = function(person) {
    return lazy(person) ? strength(person) * lazyPulling : strength(person)
  }

  var totalPulling = function(team){
    return sum(map(pulling, team))
  }

  var winner = function(team1, team2){
    return totalPulling(team1) > totalPulling(team2) ? team1 : team2
  }

  var beat = function(team1, team2){
    return winner(team1, team2) == team1
  }

  return {strength: strength, lazy: lazy, pulling: pulling,
          totalPulling: totalPulling, winner: winner, beat: beat}
}

// Example usage
var model = function() {
  var lazyPulling = 0.5
  var lazinessPrior = 0.3
  var tow = tugOfWarModel(lazyPulling, lazinessPrior)

  // Alice beats Bob
  condition(tow.beat(["alice"], ["bob"]))

  return tow.strength("alice")
}

var posterior = Infer({method: "MCMC", samples: 1000, burn: 500}, model)
viz(posterior)
