var causalPosterior = function(observedData){
  return Infer({method: 'MCMC', burn:1000, samples: 10000}, function() {
    var cp = uniform({a:0, b:1})  // causal power of C
    var b = uniform({a:0, b:1})   // background rate
    var obsFn = function(datum) {
