var causalPosterior = function(observedData){
  return Infer({method: 'MCMC', burn:1000, samples: 10000}, function() {
    var cp = uniform({a:0, b:1})  // causal power of C
    var b = uniform({a:0, b:1})   // background rate
    var obsFn = function(datum) {
      // noisy-or: E is caused by C or background
      var p = datum.C ? (1 - (1-cp)*(1-b)) : b
      observe(Bernoulli({p: p}), datum.E)
    }
    mapData({data: observedData}, obsFn)
    return {cp: cp, b: b}
  })
}

// Some example data: C present/absent, E present/absent
var observedData = [
  {C: true, E: true},
  {C: true, E: true},
  {C: true, E: true},
  {C: false, E: false},
  {C: false, E: false},
  {C: true, E: true},
  {C: false, E: true},
  {C: true, E: false}
]

viz.marginals(causalPosterior(observedData))
