var colors = ['black', 'blue', 'green', 'orange', 'red'];
var shapes = ['circle', 'square', 'triangle', 'star', 'cross'];
var textures = ['smooth', 'bumpy', 'ribbed', 'dotted', 'striped'];

// Training data: 4 categories, each with 3 objects
// Each category is homogeneous in shape but varies in color and texture
var observedData = [
  // category 1: all circles
  {cat: 'cat1', shape: 'circle',   color: 'red',    texture: 'smooth'},
  {cat: 'cat1', shape: 'circle',   color: 'blue',   texture: 'bumpy'},
  {cat: 'cat1', shape: 'circle',   color: 'green',  texture: 'ribbed'},
  // category 2: all squares
  {cat: 'cat2', shape: 'square',   color: 'orange', texture: 'dotted'},
  {cat: 'cat2', shape: 'square',   color: 'black',  texture: 'smooth'},
  {cat: 'cat2', shape: 'square',   color: 'red',    texture: 'striped'},
  // category 3: all triangles
  {cat: 'cat3', shape: 'triangle', color: 'blue',   texture: 'bumpy'},
  {cat: 'cat3', shape: 'triangle', color: 'green',  texture: 'dotted'},
  {cat: 'cat3', shape: 'triangle', color: 'black',  texture: 'smooth'},
  // category 4: all stars
  {cat: 'cat4', shape: 'star',     color: 'red',    texture: 'ribbed'},
  {cat: 'cat4', shape: 'star',     color: 'orange', texture: 'bumpy'},
  {cat: 'cat4', shape: 'star',     color: 'blue',   texture: 'striped'},
  // novel category: single instance
  {cat: 'cat5', shape: 'cross',    color: 'green',  texture: 'dotted'}
]

var predictives = Infer({method: 'MCMC', samples: 30000}, function(){

  // Hyperparameters for each dimension
  var phi_shape   = dirichlet(ones([shapes.length, 1]))
  var phi_color   = dirichlet(ones([colors.length, 1]))
  var phi_texture = dirichlet(ones([textures.length, 1]))

  // Concentration parameters (alpha) for each dimension
  // drawn from exponential with mean 1
  var alpha_shape   = exponential(1)
  var alpha_color   = exponential(1)
  var alpha_texture = exponential(1)

  var prototype_shape   = T.mul(phi_shape,   alpha_shape)
  var prototype_color   = T.mul(phi_color,   alpha_color)
  var prototype_texture = T.mul(phi_texture, alpha_texture)

  // Each category gets its own distribution over each dimension
  var makeCategory = mem(function(cat) {
    return {
      shapeDist:   Categorical({vs: shapes,   ps: dirichlet(prototype_shape)}),
      colorDist:   Categorical({vs: colors,   ps: dirichlet(prototype_color)}),
      textureDist: Categorical({vs: textures, ps: dirichlet(prototype_texture)})
    }
  })

  var obsFn = function(datum) {
    var cat = makeCategory(datum.cat)
    observe(cat.shapeDist,   datum.shape)
    observe(cat.colorDist,   datum.color)
    observe(cat.textureDist, datum.texture)
  }

  mapData({data: observedData}, obsFn)

  var cat5 = makeCategory('cat5')

  return {
    shape:         sample(cat5.shapeDist),
    color:         sample(cat5.colorDist),
    texture:       sample(cat5.textureDist),
    alpha_shape:   alpha_shape,
    alpha_color:   alpha_color,
    alpha_texture: alpha_texture
  }
})

