var baserate = 0.1
var numFlips = 3

var infModel = function(){
  Infer({method: 'MCMC', samples: 100}, function(){
    var choices = repeat(numFlips, function(){flip(baserate)})
    condition(sum(choices) >= 2)
    return choices[0]})
}

time(infModel, 10)

var p = 0.7

var geometric = function(p){
  return ((flip(p) == true) ? 1 : (1 + geometric(p)))
}

var transition = function(state){
  var proposed = (flip(0.5) ? state - 1 : state + 1)
  var targetScore = function(x) {
    return (x < 3 ? -Infinity : (x - 1) * Math.log(1 - p) + Math.log(p))
  }
  var acceptanceProb = Math.exp(targetScore(proposed) - targetScore(state))
  return (flip(acceptanceProb) ? proposed : state)
}

var chain = function(state, n){
  return (n == 0 ? state : chain(transition(state), n-1))
}

var samples = repeat(5000, function() {chain(3, 250)})
viz.table(samples)

var genObservations = function() {
  var trueX = [0.5]
  var trueY = [0.5]
  var obsX = [trueX[0] + gaussian(0, 0.04)]
  var obsY = [trueY[0] + gaussian(0, 0.04)]

  var genStep = function(i, trueXs, trueYs, obsXs, obsYs) {
    if (i >= 20) {
      return {trueX: trueXs, trueY: trueYs, obsX: obsXs, obsY: obsYs}
    }
    var dx = trueXs[i-1] - (i >= 2 ? trueXs[i-2] : trueXs[i-1])
    var dy = trueYs[i-1] - (i >= 2 ? trueYs[i-2] : trueYs[i-1])
    var newTrueX = trueXs[i-1] + dx + gaussian(0, 0.007)
    var newTrueY = trueYs[i-1] + dy + gaussian(0, 0.007)
    var newObsX = newTrueX + gaussian(0, 0.04)
    var newObsY = newTrueY + gaussian(0, 0.04)
    return genStep(i+1,
                   trueXs.concat([newTrueX]),
                   trueYs.concat([newTrueY]),
                   obsXs.concat([newObsX]),
                   obsYs.concat([newObsY]))
  }

  return genStep(1, trueX, trueY, obsX, obsY)
}

