var BigSet = ['a', 'b', 'c', 'd', 'e', 'f']
var SmallSet = ['a', 'b', 'c']

var sizeOfSet = function(h) { return h == 'Big' ? 6 : 3 }
var setOfHyp = function(h) { return h == 'Big' ? BigSet : SmallSet }

var model = function() {
  var hypothesis = uniformDraw(hypotheses)
  var set = setOfHyp(hypothesis)
  var obs = uniformDraw(set)
  condition(obs == 'a')
  return hypothesis
}

viz(Infer({method: 'enumerate'}, model))

var hypothesisToDist = function(hyp) {
  return (hyp == 'Big' ?
          Categorical({vs: ['a', 'b', 'c', 'd', 'e', 'f'], ps: [1/6, 1/6, 1/6, 1/6, 1/6, 1/6]}) :
          Categorical({vs: ['a', 'b', 'c'], ps: [1/3, 1/3, 1/3]}));
}

var dataSets = [['a'], ['a','a'], ['a','a','a'], ['a','a','a','a'], ['a','a','a','a','a']]

var posts = map(function(data) {
  var post = Infer({method: 'enumerate'}, function(){
    var hypothesis = flip() ? 'Big' : 'Small'
    mapData({data: data}, function(d){observe(hypothesisToDist(hypothesis),d)})
    return hypothesis
  })
  return Math.exp(post.score('Small'))
}, dataSets)

viz.bar(_.range(1, dataSets.length + 1), posts)

var fairPrior = .999;
var pseudoCounts = {a: 1, b: 1};
var fullData = repeat(20, function(){return 'h'});
var dataSizes = [0, 1, 3, 6, 10, 15, 20];

var weightPosterior = function(data) {
  return Infer({method: 'MCMC', samples: 5000}, function(){
    var fair = flip(fairPrior);
    var coinWeight = fair ? .5 : beta(pseudoCounts.a, pseudoCounts.b);
    mapData({data: data}, function(d){observe(Bernoulli({p: coinWeight}), d==='h')})
    return coinWeight;
  });
};

var meanWeights = map(function(size) {
  return expectation(weightPosterior(fullData.slice(0, size)));
}, dataSizes);

viz.line(dataSizes, meanWeights, {xLabel: 'numDataPoints', yLabel: 'Mean coin weight'});

var xSize = 4, ySize = 2
var background = reduce(function(x,acc){return acc.concat(x)}, [],
                        map(function(x){return map(function(y){return {x:x,y:y,color:0}},
                                                   _.range(ySize))},_.range(xSize)))

var layer = function(object, image) {
  return map(function(pixel){
    var hitsObject = (pixel.x >= object.xLoc) &&
        (pixel.x < (object.xLoc+object.hSize)) &&
        (pixel.y >= object.yLoc) &&
        (pixel.y < (object.yLoc+object.vSize))
    var color = hitsObject ? object.color : pixel.color
    return {x:pixel.x, y:pixel.y, color: color}
  }, image)
}

var sampleProperties = function() {
  return {xLoc: randomInteger(xSize), yLoc: randomInteger(ySize),
          hSize: 1, vSize: flip()?1:2, color: 1}
}

// simple random drift: object moves left, stays, or moves right
var drift = function(object) {
  var dx = randomInteger(3) - 1  // -1, 0, or 1
  return {xLoc: object.xLoc + dx, yLoc: object.yLoc,
          hSize: object.hSize, vSize: object.vSize, color: object.color}
}

// observed: a 1x2 red patch at position 1, then it moves to position 2
var observedImage1 = layer({xLoc:1,yLoc:0,hSize:1,vSize:2,color:1},background)
var observedImage2 = layer({xLoc:2,yLoc:0,hSize:1,vSize:2,color:1},background)

var results = Infer({method: 'enumerate'}, function() {
  var numObjects = flip() ? 1 : 2;

  var obj1 = sampleProperties()
  var obj2 = sampleProperties()

  // render first frame
  var image1_t1 = layer(obj1, background)
  var image_t1 = numObjects > 1 ? layer(obj2, image1_t1) : image1_t1

  // drift objects for second frame
  var obj1_t2 = drift(obj1)
  var obj2_t2 = drift(obj2)

  var image1_t2 = layer(obj1_t2, background)
  var image_t2 = numObjects > 1 ? layer(obj2_t2, image1_t2) : image1_t2

  condition(_.isEqual(image_t1, observedImage1))
  condition(_.isEqual(image_t2, observedImage2))

  return numObjects;
})

