        (pixel.x < (object.xLoc+object.hSize)) &&
        (pixel.y >= object.yLoc) &&
        (pixel.y < (object.yLoc+object.vSize))
    var color = hitsObject ? object.color : pixel.color
    return {x:pixel.x, y:pixel.y, color: color}
  }, image)
}

var sampleProperties = function() {
  return {xLoc: randomInteger(xSize), yLoc: randomInteger(ySize),
          hSize: 1, vSize: flip()?1:2, color: 1}
}

// simple random drift: object moves left, stays, or moves right
var drift = function(object) {
  var dx = randomInteger(3) - 1  // -1, 0, or 1
  return {xLoc: object.xLoc + dx, yLoc: object.yLoc,
          hSize: object.hSize, vSize: object.vSize, color: object.color}
}

// observed: a 1x2 red patch at position 1, then it moves to position 2
var observedImage1 = layer({xLoc:1,yLoc:0,hSize:1,vSize:2,color:1},background)
var observedImage2 = layer({xLoc:2,yLoc:0,hSize:1,vSize:2,color:1},background)

var results = Infer({method: 'enumerate'}, function() {
  var numObjects = flip() ? 1 : 2;

  var obj1 = sampleProperties()
  var obj2 = sampleProperties()

  // render first frame
  var image1_t1 = layer(obj1, background)
  var image_t1 = numObjects > 1 ? layer(obj2, image1_t1) : image1_t1

  // drift objects for second frame
  var obj1_t2 = drift(obj1)
  var obj2_t2 = drift(obj2)

  var image1_t2 = layer(obj1_t2, background)
  var image_t2 = numObjects > 1 ? layer(obj2_t2, image1_t2) : image1_t2

  condition(_.isEqual(image_t1, observedImage1))
  condition(_.isEqual(image_t2, observedImage2))

  return numObjects;
})

