var polyaProb = function(sequence) {
  return Infer({method: 'enumerate'}, function() {
    var urn = ['b', 'w']
    var drawSequence = function(urn, remaining) {
      if (remaining === 0) return []
      var ball = categorical({vs: urn, ps: map(function(x){1}, urn)})
      var newUrn = urn.concat([ball])
      return [ball].concat(drawSequence(newUrn, remaining - 1))
    }
    var s = drawSequence(urn, sequence.length)
    condition(_.isEqual(s, sequence))
    return true
  })
}

