// A single agent who maximizes (chooses most likely outcome)
var maximizingAgent = function() {
  // Posterior over coin weight given 4 heads in 5 flips
  var weight = sample(Infer({method: 'MCMC', samples: 10000}, function() {
    var w = sample(Beta({a: 1, b: 1}));
    observe(Binomial({n: 5, p: w}), 4);
    return w;
  }));
  // Choose the most likely next outcome
  return weight > 0.5 ? 'heads' : 'tails';
};

// A single agent who samples once from their belief distribution
var samplingAgent = function() {
  return sample(Infer({method: 'MCMC', samples: 10000}, function() {
    var w = sample(Beta({a: 1, b: 1}));
    observe(Binomial({n: 5, p: w}), 4);
    return flip(w) ? 'heads' : 'tails';
  }));
};

// Population of maximizing agents
var maximizingPopulation = Infer({method: 'forward', samples: 1000}, function() {
  // Posterior mean given 4 heads in 5 flips (Beta(5,2))
  // Most likely outcome is heads since E[w] = 5/7 > 0.5
  var posteriorPredictive = Infer({method: 'MCMC', samples: 1000}, function() {
    var w = sample(Beta({a: 5, b: 2}));
    return flip(w) ? 'heads' : 'tails';
  });
  // Maximizing agent picks the MAP
  var pHeads = Math.exp(posteriorPredictive.score('heads'));
  return pHeads > 0.5 ? 'heads' : 'tails';
});

// Population of sampling agents (each uses one sample)
var samplingPopulation = Infer({method: 'forward', samples: 1000}, function() {
  var w = sample(Beta({a: 5, b: 2}));
  return flip(w) ? 'heads' : 'tails';
});

print("Maximizing agent population:");
viz(maximizingPopulation);

print("Sampling agent population:");
viz(samplingPopulation);

