var actionPrior = Categorical({vs: ['red', 'green', 'blue'], ps: [1/3, 1/3, 1/3]})

var diceWeights = {
  'A': {red: 0, green: 0.2, blue: 0.8},
  'B': {red: 0.4, green: 0.6, blue: 0}
}

var diePrior = Categorical({vs: ['A', 'B'], ps: [0.5, 0.5]})

var roll = function(die, face) {
  return diceWeights[die][face]
}

var teacher = function(die, depth) {
  return Infer(function() {
    var face = sample(actionPrior)
    var learnerDist = learner(face, depth)
    observe(learnerDist, die)
    return face
  })
}

var learner = function(face, depth) {
  return Infer(function() {
    var die = sample(diePrior)
    if (depth == 0) {
      factor(Math.log(roll(die, face)))
    } else {
      observe(teacher(die, depth - 1), face)
    }
    return die
  })
}

