var worlds = [0, 1, 2, 3]
var worldPrior = Categorical({vs: worlds, ps: [1/4, 1/4, 1/4, 1/4]})

var sentences = ['all', 'some', 'none']
var sentencePrior = Categorical({vs: sentences, ps: [1/3, 1/3, 1/3]})

var meaning = function(sentence, world) {
  return (sentence == 'all'  ? world == 3 :
          sentence == 'some' ? world > 0  :
          sentence == 'none' ? world == 0 :
          true)
}

var speaker = function(world, depth) {
  return Infer({method: 'enumerate'}, function() {
    var sentence = sample(sentencePrior)
    condition(sample(listener(sentence, depth)) == world)
    return sentence
  })
}

var listener = function(sentence, depth) {
  return Infer({method: 'enumerate'}, function() {
    var world = sample(worldPrior)
    condition(depth == 0 ?
              meaning(sentence, world) :
              sample(speaker(world, depth - 1)) == sentence)
    return world
  })
}

