var detectingBlickets = function(evidence, params) {
  return Infer({method: 'enumerate'}, function() {
    var blicketPower = params.blicketPower;
    var nonBlicketPower = params.nonBlicketPower;
    var baseRate = params.baseRate;

    var blicket = mem(function(component) {
      return flip(baseRate);
    });

    var power = function(component) {
      return blicket(component) ? blicketPower : nonBlicketPower;
    };

    var machineOn = function(components) {
      return any(function(c) { return flip(power(c)); }, components);
    };

    observe(Bernoulli({p: machineOn(evidence.components)}), evidence.machineOn);

    return blicket('A');
  });
};

// Backwards blocking example:
// A and B together make the machine go. Does A alone make the machine go?
var evidence = {
  components: ['A', 'B'],
  machineOn: true
};

var params = {
  blicketPower: 0.9,
  nonBlicketPower: 0.05,
  baseRate: 0.4
};

viz(detectingBlickets(evidence, params));

var detectingBlickets = function(evidence, params) {
  return Infer({method: 'enumerate'}, function() {
    var blicket = mem(function(block) { flip(params.blicketBaseRate) });
    var power = function(block) { blicket(block) ? params.blicketPower : params.nonBlicketPower };
    var machine = function(blocks) {
      return (blocks.length == 0 ?
              flip(params.machineSpontaneouslyGoesOff) :
              flip(power(first(blocks))) || machine(rest(blocks)));
    };
    map(function(blocks) { condition(machine(blocks)) }, evidence);
    return blicket('A');
  });
};

var dataAnalysis = Infer({method: 'MCMC', samples: 5000, lag: 20}, function() {
  var params = {
    blicketBaseRate: uniform(0, 1),
    blicketPower: uniform(0, 1),
    nonBlicketPower: uniform(0, 1),
    machineSpontaneouslyGoesOff: uniform(0, 1)
  };

  // Schematic data from Sobel et al. (2004)
  // Each entry is [evidence, observed probability that A is a blicket]
  var data = [
    {evidence: [['A', 'B']], nA: 3, nTotal: 12},
    {evidence: [['A', 'B'], ['B']], nA: 1, nTotal: 12}
  ];

  map(function(d) {
    var predictive = detectingBlickets(d.evidence, params);
    observe(Binomial({p: Math.exp(predictive.score(true)), n: d.nTotal}), d.nA);
  }, data);

  return params;
});

viz.marginals(dataAnalysis);

