var fairness = function(observed_data) {
  var prior = Infer({method: 'MCMC', samples: 10000, burn: 1000}, function() {
    var isFair = flip(0.999)
    var isTwoFaced = isFair ? false : flip(0.9)
    var weight = isFair ? 0.5 : (isTwoFaced ? 1.0 : uniform(0, 1))
    var obsFn = function(datum) { observe(Bernoulli({p: weight}), datum === 'H') }
    mapData({data: observed_data}, obsFn)
    return weight
  })
  return prior
}

