// Define the space of possible functions
var randomArithmeticExpression = function() {
  if (flip(0.3)) {
    var op = uniformDraw(['+', '-', '*', '/']);
    var a = randomArithmeticExpression();
    var b = randomArithmeticExpression();
    return function(x) {
      if (op === '+') return a(x) + b(x);
      if (op === '-') return a(x) - b(x);
      if (op === '*') return a(x) * b(x);
      if (op === '/') return a(x) / b(x);
    };
  } else {
    if (flip(0.5)) {
      return function(x) { return x; };
    } else {
      var c = uniformDraw([1, 2, 3, 4, 5]);
      return function(x) { return c; };
    }
  }
};

var model = function() {
  var f = randomArithmeticExpression();

  var y1 = f(1);
