  condition(isInt(y1) && isInt(y2));
  condition(y1 === 1);
  condition(y2 === 4);

  var y3 = f(3);
  condition(isInt(y3));

  return {y3: y3};
};

var results = Infer({method: 'enumerate', maxExecutions: 10000}, model);
