var actions = ['a', 'b', 'c'];

var utility = {
  'a': 3,
  'b': 1,
  'c': 2
};

var chooseAction = function(deceive) {
  if (deceive) {
    // Choose the action with the lowest utility (misdirection)
    return 'b'; // or sample from non-optimal actions
  } else {
    return argMax(function(a) { return utility[a]; }, actions);
  }
};

// More principled version:
var chooseAction2 = function(deceive) {
  return Infer({method: 'enumerate'}, function() {
    var action = uniformDraw(actions);
    if (deceive) {
      // Prefer actions that are NOT the best action
      factor(-utility[action]);
    } else {
      factor(utility[action]);
    }
    return action;
  });
};

// Sally is deceptive
var deceive = true;
var actionDist = chooseAction2(deceive);
viz(actionDist);

// If Sally is deceptive and chooses action "b":
// "b" has utility 1 (the lowest), so it's consistent with deception.
// A deceptive Sally would avoid her true preference (action "a" with utility 3)
// and instead choose lower-utility actions to mislead the observer.
print("Most likely action if deceptive: " + sample(actionDist));

