// Rule-based number game model

var genSetFromRule = function(rule) {
  if (rule === 'odd') {
    return _.range(1, 101, 2);
  } else if (rule === 'even') {
    return _.range(2, 102, 2);
  } else if (rule === 'squares') {
    return map(function(x) { return x * x; }, _.range(1, 11));
  } else if (rule === 'cubes') {
    return map(function(x) { return x * x * x; }, _.range(1, 6));
  } else if (rule === 'primes') {
    var isPrime = function(n) {
      if (n < 2) return false;
      var factors = _.range(2, Math.floor(Math.sqrt(n)) + 1);
      return all(function(f) { return n % f !== 0; }, factors);
    };
    return filter(isPrime, _.range(2, 101));
  } else if (rule.slice(0, 9) === 'multiples') {
    var n = parseInt(rule.slice(10));
    return _.range(n, 101, n);
  } else if (rule.slice(0, 6) === 'powers') {
    var base = parseInt(rule.slice(7));
    var powers = [];
    var x = base;
    while (x <= 100) {
      powers.push(x);
      x *= base;
    }
    return powers;
  } else {
    return [];
  }
};

var rules = ['odd', 'even', 'squares', 'cubes', 'primes'].concat(
  map(function(n) { return 'multiples_' + n; }, _.range(2, 11))
).concat(
  map(function(n) { return 'powers_' + n; }, _.range(2, 11))
);

var getSetFromHypothesis = function(hypothesis) {
  return genSetFromRule(hypothesis);
};

var numberGameModel = function(observations) {
  var hypothesis = uniformDraw(rules);
  var set = getSetFromHypothesis(hypothesis);

  // All observations must be in the set
  var allInSet = all(function(obs) { return set.indexOf(obs) !== -1; }, observations);
  condition(allInSet);

  return hypothesis;
};

