// Causal Support model
// The key difference from Causal Power: instead of estimating a continuous power parameter,
// we infer whether there IS a causal relation (graph structure) at all.

var causalSupport = function(contingencyTable) {
  // contingencyTable = {e1c1, e1c0, e0c1, e0c0}
  // e1c1: effect present, cause present
  // e1c0: effect present, cause absent
  // e0c1: effect absent, cause present
  // e0c0: effect absent, cause absent

  return Infer({method: 'MCMC', samples: 10000}, function() {
    // Infer whether there is a causal relation (graph structure)
    var causalRelation = flip(0.5); // prior over graph structures

    // Background rate of effect (always present)
    var b = uniform(0, 1);

    if (causalRelation) {
      // If there IS a causal relation, sample a causal power
      var w = uniform(0, 1);

      // Noisy-OR likelihood
      // P(E=1 | C=1) = 1 - (1-b)(1-w)
      // P(E=1 | C=0) = b
      var pE1C1 = 1 - (1 - b) * (1 - w);
      var pE1C0 = b;

      observe(Binomial({n: contingencyTable.e1c1 + contingencyTable.e0c1, 
                        p: pE1C1}), contingencyTable.e1c1);
      observe(Binomial({n: contingencyTable.e1c0 + contingencyTable.e0c0, 
                        p: pE1C0}), contingencyTable.e1c0);
    } else {
      // If there is NO causal relation, C has no effect on E
      // P(E=1 | C=1) = b
      // P(E=1 | C=0) = b
      var pE1C1 = b;
      var pE1C0 = b;

      observe(Binomial({n: contingencyTable.e1c1 + contingencyTable.e0c1, 
                        p: pE1C1}), contingencyTable.e1c1);
      observe(Binomial({n: contingencyTable.e1c0 + contingencyTable.e0c0, 
                        p: pE1C0}), contingencyTable.e1c0);
    }

    return {causalRelation: causalRelation};
  });
};

