// Simulate the critical cases from Griffiths & Tenenbaum (2005) Fig. 1
// Cases where E occurs equally often with and without C

// Case 1: E never occurs (0/N with C, 0/N without C)
// Case 2: E always occurs (N/N with C, N/N without C)
// Case 3: E occurs sometimes equally (e.g., 4/8 with C, 4/8 without C)

var makeCPModel = function(observedData) {
  return Infer({method: 'MCMC', samples: 10000, lag: 2}, function() {
    var cp = uniform(0, 1);
    var b = uniform(0, 1);

    mapData({data: observedData}, function(datum) {
      var pE = datum.C ? (1 - (1 - cp) * (1 - b)) : b;
      observe(Bernoulli({p: pE}), datum.E);
    });

    return {cp};
  });
};

