}

var makeIntervalHypothesisSpace = function(start, end) {
  var intervals = [];
  var result = [];
  for (var i = start; i <= end; i++) {
    for (var j = i + 1; j <= end; j++) {
      result.push('interval_' + i + '_' + j);
    }
  }
  return result;
}

