  var powerRules = map(function(base) {return 'powers_of_' + base}, _.range(1, 12));
  var intervalRules = makeIntervalHypothesisSpace(1, maxNumber);
  return multipleRules.concat(powerRules).concat(['evens', 'odds']).concat(intervalRules);
} 

