// Causal Power model (for reference/comparison)
var causalPowerModel = function(data) {
  Infer({method: 'MCMC', samples: 5000}, function() {
    var b = uniform(0, 1); // background rate
    var p = uniform(0, 1); // causal power of C

    mapData({data: data}, function(d) {
      // P(E=1 | C, b, p) = b + p*C - b*p*C (noisy-OR)
      var pE = d.C ? (b + p - b * p) : b;
      observe(Bernoulli({p: pE}), d.E);
    });

    return {b: b, p: p};
  });
};

// Causal Support model
// Instead of estimating causal power, infer whether a causal relation exists
var causalSupportModel = function(data) {
  Infer({method: 'MCMC', samples: 5000}, function() {
    // Binary choice: does C cause E?
    var causalRelation = flip(0.5);

    var b = uniform(0, 1); // background rate
    var p = causalRelation ? uniform(0, 1) : 0; // causal power only if relation exists

    mapData({data: data}, function(d) {
      // P(E=1 | C, b, p) = b + p*C - b*p*C (noisy-OR)
      var pE = d.C ? (b + p - b * p) : b;
      observe(Bernoulli({p: pE}), d.E);
    });

    return causalRelation;
  });
};

// Example data: C present and E present 3 times, C absent and E absent 3 times
var data1 = [{C: true, E: true}, {C: true, E: true}, {C: true, E: true},
             {C: false, E: false}, {C: false, E: false}, {C: false, E: false}];

