// Case 3: E occurs sometimes equally (e.g., 4/8 with C, 4/8 without C)

var makeCPModel = function(observedData) {
  return Infer({method: 'MCMC', samples: 10000, lag: 2}, function() {
    var cp = uniform(0, 1);
    var b = uniform(0, 1);

    mapData({data: observedData}, function(datum) {
      var pE = datum.C ? (1 - (1 - cp) * (1 - b)) : b;
      observe(Bernoulli({p: pE}), datum.E);
    });

    return {cp};
  });
};

var makeCSModel = function(observedData) {
  return Infer({method: 'MCMC', samples: 10000, lag: 2}, function() {
    var relation = flip();
    var cp = uniform(0, 1);
    var b = uniform(0, 1);

    var noisyOrMarginal = function(C) {
      return Infer({method: 'enumerate'}, function() {
        return (relation && C && flip(cp)) || flip(b);
      });
    };

    mapData({data: observedData}, function(datum) {
      observe(noisyOrMarginal(datum.C), datum.E);
    });

    return {relation};
  });
