// Helper function to time an inference
var timeIt = function(func) {
  var start = _.now();
  func();
  var end = _.now();
  return end - start;
}

// Blicket detector model
var blicketModel = function(baseRate, obs) {
  var blicket = mem(function(block) { flip(baseRate) });
  var power = function(block) { blicket(block) ? 0.9 : 0.05 };
  var machineBeeps = function(blocks) {
    return any(function(b) { flip(power(b)) }, blocks);
  };
  condition(machineBeeps(obs.blocks) == obs.beeps);
  return blicket('A');
};

// Inference using rejection sampling
var rejectionFn = function(baseRate, obs, numSamples) {
  return Infer({method: 'rejection', samples: numSamples}, function() {
    return blicketModel(baseRate, obs);
  });
};

// Inference using enumeration
var enumerationFn = function(baseRate, obs, numSamples) {
  return Infer({method: 'enumerate'}, function() {
    return blicketModel(baseRate, obs);
  });
};

// Get response (probability that A is a blicket) and RT
var getResponseAndRT = function(baseRate, obs, numSamples, method) {
  var inferFn = method == 'rejection' ? rejectionFn : enumerationFn;
  var rt = timeIt(function() { inferFn(baseRate, obs, numSamples) });
  var dist = inferFn(baseRate, obs, numSamples);
  var response = Math.exp(dist.score(true));
  return { response: response, RT: rt };
};

