var tugOfWar = function(team1, team2) {
  var strength = mem(function(person) { return gaussian(0, 1) })
  var lazy = function(person) { return flip(0.25) }
  var totalPull = function(team) {
    return sum(map(function(person) {
      return lazy(person) ? strength(person) / 2 : strength(person)
    }, team))
  }
  var winner = totalPull(team1) > totalPull(team2) ? 'team1' : 'team2'
  return winner
}

viz(Infer({method: 'forward', samples: 10000}, function() {
  var w1 = tugOfWar(['alice', 'bob'], ['sue', 'tom'])
  var w2 = tugOfWar(['alice', 'bob'], ['sue', 'tom'])
  var w3 = tugOfWar(['alice', 'bob'], ['sue', 'tom'])
  return w1 == 'team1' && w2 == 'team1' && w3 == 'team1'
}))

var model = function() {
  var strength = mem(function(person) { return Math.max(gaussian(1, 1), 0.01) })
  var cleverness = mem(function(person) { return Math.max(gaussian(1, 1), 0.01) })
  var lazy = function(person) { return flip(1/3) }

  // Tug of war depends mostly on strength
  var tugPulling = function(person) {
    return lazy(person) ? strength(person) / 2 : strength(person)
  }
  var totalTugPulling = function(team) { return sum(map(tugPulling, team)) }
  var tugWinner = function(team1, team2) {
    return totalTugPulling(team1) > totalTugPulling(team2) ? team1 : team2
  }
  var tugBeat = function(team1, team2) { return _.isEqual(tugWinner(team1, team2), team1) }

  // Table tennis depends on both strength and cleverness, but more on cleverness
  var tennisPower = function(person) {
    return lazy(person) ? (0.3 * strength(person) + 0.7 * cleverness(person)) / 2
                        : (0.3 * strength(person) + 0.7 * cleverness(person))
  }
  var totalTennisPower = function(team) { return sum(map(tennisPower, team)) }
  var tennisWinner = function(team1, team2) {
    return totalTennisPower(team1) > totalTennisPower(team2) ? team1 : team2
  }
  var tennisBeat = function(team1, team2) { return _.isEqual(tennisWinner(team1, team2), team1) }

  // Observe that bob & mary beat tom & sue at tug of war
  condition(tugBeat(['bob', 'mary'], ['tom', 'sue']))
  // Observe that bob & mary beat tom & sue at table tennis
  condition(tennisBeat(['bob', 'mary'], ['tom', 'sue']))

  return {
    bobStrength: strength('bob'),
    bobCleverness: cleverness('bob')
  }
}

var dist = Infer({method: 'MCMC', samples: 5000}, model)

viz.marginals(dist)

