// Helper function to evaluate inference methods
var trueExpectation = 0.5; // Will be updated after first run

var runInference = function(innerOpt, outerOpt, numRuns) {
  var times = [];
  var expectations = [];

  var runOnce = function() {
    var startTime = _.now();

    var outerDist = Infer(outerOpt, function() {
      var x = flip(0.5);

      var innerDist = Infer(innerOpt, function() {
        var y = flip(x ? 0.7 : 0.3);
        return y;
      });

      var innerExpectation = Math.exp(innerDist.score(true));
      factor(innerExpectation > 0.5 ? 0 : -Infinity);

      return x ? 1 : 0;
    });

    var endTime = _.now();
    times.push(endTime - startTime);

    var exp = expectation(outerDist, function(x) { return x; });
    expectations.push(exp);
  };

  var i = 0;
  while (i < numRuns) {
    runOnce();
    i++;
  }

  var meanTime = _.mean(times);
  var meanExp = _.mean(expectations);
  var varExp = _.mean(map(function(e) { return Math.pow(e - meanExp, 2); }, expectations));
  var bias = meanExp - trueExpectation;

  return {
    meanTime: meanTime,
    varianceOfExpectation: varExp,
    bias: bias,
    meanExpectation: meanExp
  };
};

// Define inner and outer options
var innerOpt = {method: 'enumerate'};
var outerOpt = {method: 'enumerate'};

var numRuns = 5;
var results = runInference(innerOpt, outerOpt, numRuns);
print("Inner method: " + innerOpt.method);
print("Outer method: " + outerOpt.method);
print("Mean run time (ms): " + results.meanTime);
print("Variance of expectation: " + results.varianceOfExpectation);
print("Mean expectation: " + results.meanExpectation);
print("Bias (deviation from true expectation): " + results.bias);

