// Two objects: one more likely (salient), one less likely
// Two utterances: one cheaper, one more costly
var objects = ["obj1", "obj2"];
var utterances = ["word1", "word2"];

// Prior over objects: obj1 is more likely
var objectPrior = function() {
  return categorical({ps: [0.7, 0.3], vs: objects});
};

// Utterance prior: word1 is cheaper
var utterancePrior = function() {
  return categorical({ps: [0.7, 0.3], vs: utterances});
};

// Both words mean the same thing (apply to both objects)
var meaning = function(utterance, object) {
  return true; // both words apply to both objects
};

// Cost: word1 is cheaper (cost 0), word2 is more costly (cost 1)
var cost = function(utterance) {
  return utterance === "word1" ? 0 : 1;
};

var alpha = 1;

var literalListener = function(utterance) {
  return Infer({method: "enumerate"}, function() {
    var object = objectPrior();
    condition(meaning(utterance, object));
    return object;
  });
};

var speaker = function(object) {
  return Infer({method: "enumerate"}, function() {
    var utterance = utterancePrior();
    factor(alpha * (literalListener(utterance).score(object) - cost(utterance)));
    return utterance;
  });
};

var pragmaticListener = function(utterance) {
  return Infer({method: "enumerate"}, function() {
    var object = objectPrior();
    factor(speaker(object).score(utterance));
    return object;
  });
};

print("Pragmatic listener hears 'word1' (cheap):");
viz(pragmaticListener("word1"));

print("Pragmatic listener hears 'word2' (costly):");
viz(pragmaticListener("word2"));

// World model: causal chains
// Direct: John bumped the vase (JBV), vase broke (VB)
// Indirect: John bumped the lamp (JBL), lamp bumped vase, vase broke (VB)

var worldPrior = function() {
  // Direct causation is more likely than indirect
  return categorical({vs: ["JBV && VB", "JBL && VB"], ps: [0.7, 0.3]})
}

// Two utterances with different lengths (costs)
var utterances = ["John broke the vase", "John caused the vase to break"]

var cost = function(utterance) {
  return utterance.length / 20  // scale cost
}

// Lexical uncertainty: possible meanings for each utterance
// "John broke the vase" could mean JBV or JBL is the key event
// "John caused the vase to break" could mean JBV or JBL is the key event
var possibleLexicons = [
  // Lexicon 1: "broke" -> JBV, "caused to break" -> JBV
  {
    "John broke the vase": ["JBV && VB"],
    "John caused the vase to break": ["JBV && VB", "JBL && VB"]
  },
  // Lexicon 2: "broke" -> JBV, "caused to break" -> JBL
  {
    "John broke the vase": ["JBV && VB"],
    "John caused the vase to break": ["JBL && VB"]
  },
  // Lexicon 3: "broke" -> JBL, "caused to break" -> JBV
  {
    "John broke the vase": ["JBL && VB"],
