// Helper functions
var butLast = function(xs) {
  return xs.slice(0, xs.length - 1);
};

var uniformDraw = function(xs) {
  return xs[Math.floor(Math.random() * xs.length)];
};

// Model parameters
var alpha = 1; // speaker optimality
var costWeight = 0.1;
var priorCounts = {
  bluecircle: [1, 1, 1, 1],
  redsquare: [1, 1, 1, 1]
};

var objects = ['bluecircle', 'redsquare'];
var words = ['word1', 'word2', 'word3', 'word4'];

// Utterances: all single words and all pairs of words
var singleWords = words;
var wordPairs = [];
for (var i = 0; i < words.length; i++) {
  for (var j = i + 1; j < words.length; j++) {
    wordPairs.push(words[i] + '+' + words[j]);
  }
}
var utterances = singleWords.concat(wordPairs);

var utteranceCost = function(utt) {
  var numWords = utt.split('+').length;
  return numWords;
};

// Sample a lexicon from Beta priors
var sampleLexicon = function() {
  return {
    bluecircle: map(function(c) { return beta(c, 2 - c); }, priorCounts.bluecircle),
    redsquare: map(function(c) { return beta(c, 2 - c); }, priorCounts.redsquare)
  };
};

// Meaning of an utterance given a lexicon
// For multi-word utterances, take the product of individual word meanings
var meaning = function(utt, obj, lexicon) {
  var wordList = utt.split('+');
  var objIndex = objects.indexOf(obj);
  var wordMeanings = map(function(w) {
    var wordIndex = words.indexOf(w);
    return lexicon[obj][wordIndex];
  }, wordList);
  return reduce(function(a, b) { return a * b; }, 1, wordMeanings);
};

// Literal listener
var L0 = function(utt, lexicon) {
  return Infer({ method: 'enumerate' }, function() {
    var obj = uniformDraw(objects);
    var m = meaning(utt, obj, lexicon);
    factor(Math.log(m));
    return obj;
  });
};

// Pragmatic speaker
var S1 = function(obj, lexicon) {
  return Infer({ method: 'enumerate' }, function() {
    var utt = uniformDraw(utterances);
    var L = L0(utt, lexicon);
    var utility = L.score(obj) - costWeight * utteranceCost(utt);
    factor(alpha * utility);
    return utt;
  });
};

// Speaker with lexical uncertainty
var S_uncertain = function(obj) {
  return Infer({ method: 'forward', samples: 1000 }, function() {
    var lexicon = sampleLexicon();
    var utt = sample(S1(obj, lexicon));
    return utt;
  });
};

// Visualize speaker choices for each object
print("Speaker choices for bluecircle:");
viz(S_uncertain('bluecircle'));

print("Speaker choices for redsquare:");
viz(S_uncertain('redsquare'));

