var objects = [{shape: "circle", color: "blue", size: "small"},
               {shape: "circle", color: "blue", size: "big"},
               {shape: "circle", color: "red", size: "small"}]

// Simple lexicon
var wordMeaning = function(word, obj) {
  if (word == "circle") return obj.shape == "circle"
  if (word == "square") return obj.shape == "square"
  if (word == "blue") return obj.color == "blue"
  if (word == "red") return obj.color == "red"
  if (word == "big") return obj.size == "big"
  if (word == "small") return obj.size == "small"
  return true // "." and other words are vacuously true
}

// Meaning of an utterance (list of words) for an object
// Returns true if all words in the utterance are true of the object
var meaning = function(utt, obj) {
  return all(function(word) { return wordMeaning(word, obj) }, utt)
}

// Grammar: given a partial utterance, sample the next word
var extend = function(prefix) {
  if (prefix.length == 0) {
    // Start with a noun or adjective
    return sample(Categorical({vs: ["circle", "blue", "red", "big", "small"], 
                               ps: [0.3, 0.2, 0.2, 0.15, 0.15]}))
  } else {
    var lastWord = prefix[prefix.length - 1]
    // After a noun, end the utterance
    if (lastWord == "circle" || lastWord == "square") {
      return "."
    } else {
      // After an adjective, can add another adjective or a noun
      return sample(Categorical({vs: ["circle", "blue", "red", "big", "small", "."],
                                 ps: [0.3, 0.1, 0.1, 0.1, 0.1, 0.3]}))
    }
  }
}

// Sample a complete utterance by iteratively extending
var sampleUtt = function(prefix) {
  var nextWord = extend(prefix)
  if (nextWord == ".") {
    return prefix
  } else {
    return sampleUtt(prefix.concat([nextWord]))
  }
}

