      var logProbPrefix = function(soFar, remaining) {
        if (remaining.length == 0) return 0
        // next step: extend soFar to soFar+next_tokens
        // figure out how many tokens were added in this step
        // extend adds either [noun, "."] (2 tokens) or [adj] (1 token)
        var nextToken = remaining[0]
        var isNoun = _.includes(nouns, nextToken)
        var nextExt = isNoun ? soFar.concat([nextToken, "."]) : soFar.concat([nextToken])
        var extLen = nextExt.length - soFar.length
        var score = S1_extend(soFar, obj).score(nextExt)
        var newRemaining = remaining.slice(extLen)
        return score + logProbPrefix(nextExt, newRemaining)
      }
      return logProbPrefix([], pref)
    }
    factor(prefixProb(prefix))
    return obj
  })
})

// Show what the incremental listener infers from various prefixes
