viz(L1_incremental(["big"]))

display("After hearing 'blue':")
viz(L1_incremental(["blue"]))

display("After hearing 'big', 'blue':")
viz(L1_incremental(["big", "blue"]))

display("After hearing 'big', 'blue', 'circle', '.':")
viz(L1_incremental(["big", "blue", "circle", "."]))
