// we represent objects as strings of properties.
var objects = ["big blue circle",
               "big green circle",
               "small blue square"]

// a "grammar" to define the utterances 
var adjs = ["green", "blue", "big", "small"]
var nouns = ["circle", "square"]
var extend = function(prefix){
  if(prefix.length==2 || flip(0.5)){
    return prefix.concat([uniformDraw(nouns), "."])
  } else {
    return prefix.concat([uniformDraw(adjs)])
  }
}

// complete meaning function (only for complete utterances ending in ".")
var completeMeaning = function(utterance, obj){
  var firstWordMeaning = _.includes(obj, utterance[0])?1:0.01
  return utterance.length==1 ? firstWordMeaning : firstWordMeaning * completeMeaning(_.drop(utterance),obj)
}

// sample a completion of a prefix
var sampleCompletion = function(prefix){
  return _.last(prefix) == "." ? prefix : sampleCompletion(extend(prefix))
}

// incremental meaning as expectation over completions
var incrementalMeaning = function(prefix, obj, nSamples){
  var nSamples = nSamples==undefined ? 100 : nSamples
  var completions = repeat(nSamples, function(){ sampleCompletion(prefix) })
  var meanings = map(function(c){ completeMeaning(c, obj) }, completions)
  return sum(meanings) / nSamples
}

var L0_expected = cache(function(prefix) {
  return Infer(function(){
    var obj = uniformDraw(objects)
    factor(Math.log(incrementalMeaning(prefix, obj)))
    return obj
  })
})

var alpha = 4
var S1_extend_expected = cache(function(prefix, target) {
  return Infer(function(){
    var utt = extend(prefix)
    factor(alpha * L0_expected(utt).score(target))
    return utt
  })
})

var sampleUttS1_expected = function(target, prefix) {
  var prefix = prefix==undefined ? [] : prefix
  return _.last(prefix) == "." ? prefix : sampleUttS1_expected(target, sample(S1_extend_expected(prefix, target)))
}

// Compare incremental meaning (expectation over completions) for a prefix
