  "dog": function(obj) { return obj.dog },
  "big": function(obj) { return obj.big },
  "black": function(obj) { return obj.black },
  "friendly": function(obj) { return obj.friendly }
}

// Compose word meanings intersectively (conjunction)
var meaning = function(utterance, obj) {
  var words = utterance.split(" ")
  return all(function(word) { return wordMeanings[word](obj) }, words)
}

// Objects in the world
