// True weight of the coin
var trueWeight = 0.9;

// Number of observations
var numObs = 10;

// Generate observations from the true weight
var observations = repeat(numObs, function() { return flip(trueWeight); });

// Count heads in observations
var numHeads = sum(map(function(x) { return x ? 1 : 0; }, observations));

// The inference model: infer coin weight from observations
var inferWeight = function(numSamples) {
  return Infer({method: 'rejection', samples: numSamples}, function() {
    var weight = uniform(0, 1);
    var obsFn = function(obs) {
      observe(Bernoulli({p: weight}), obs);
    };
    mapData({data: observations}, obsFn);
    return weight;
  });
};

// Simulate a person making a decision with a given number of samples
var simulatePerson = function(numSamples) {
  // Start timing
  var startTime = numSamples; // proxy for response time

  // Get posterior over weight
  var weightDist = inferWeight(numSamples);

  // Sample a weight from posterior
  var sampledWeight = sample(weightDist);

  // Predict next flip based on sampled weight
  var prediction = sampledWeight > 0.5;

  // True next flip
  var nextFlip = flip(trueWeight);

  // Correct if prediction matches actual
  var correct = prediction === nextFlip;

  return {
    correct: correct,
    responseTime: numSamples,
    prediction: prediction,
    nextFlip: nextFlip
  };
};

// Compute average reward over many trials for different sample counts
var sampleCounts = [1, 2, 5, 10, 20, 50];

var results = map(function(n) {
  var numTrials = 100;
  var trials = repeat(numTrials, function() { return simulatePerson(n); });
  var avgCorrect = mean(map(function(t) { return t.correct ? 1 : 0; }, trials));
  var avgResponseTime = n; // proportional to number of samples
  return {
    numSamples: n,
    accuracy: avgCorrect,
    responseTime: avgResponseTime,
    // Simple reward: accuracy minus cost of time
    reward: avgCorrect - 0.01 * avgResponseTime
  };
}, sampleCounts);

print("numSamples | accuracy | responseTime | reward");
map(function(r) {
  print(r.numSamples + " | " + r.accuracy.toFixed(3) + " | " + r.responseTime + " | " + r.reward.toFixed(3));
}, results);

// Visualize accuracy vs number of samples
viz.bar(map(function(r) { return r.numSamples; }, results),
        map(function(r) { return r.accuracy; }, results));

var trueWeight = 0.8
var numObs = 20

var reward = function(opt){
  // sample observed data: number k of heads
  var k = binomial(trueWeight, numObs)

  // simulate person's decision making
  var start = _.now()
  var posterior = Infer(opt, function(){
    var weight = uniform(0, 1)
    observe(Binomial({p: weight, n: numObs}), k)
    // return predicted next observation
    return flip(weight)
  })
  // choice is most likely outcome
  var choice = posterior.MAP().val
  var end = _.now()

  // reward combines accuracy and decision time.
  var rt = end - start
  var trueNext = flip(trueWeight)
  var correct = (choice == trueNext)
  var reward = correct - 0.001 * rt

  return reward
}

