var inferEmotion = function(observedMa, observedMo, observedEh, observedEa) {
  return Infer({method: 'MCMC', samples: 5000}, function() {
    // Prior over emotion: a real number, roughly in [-10, 10]
    var emotion = gaussian(0, 5);

    // Predicted display from this emotion
    var display = emoDisplay(emotion);

    // Observe each facial feature with some noise
    observe(Gaussian({mu: display.ma, sigma: 1}), observedMa);
    observe(Gaussian({mu: display.mo, sigma: 1}), observedMo);
    observe(Gaussian({mu: display.eh, sigma: 1}), observedEh);
    observe(Gaussian({mu: display.ea, sigma: 1}), observedEa);

    return emotion;
  });
}

// Example: observe a happy-looking face (positive mouth angle, raised brows)
var happyFaceEmotion = inferEmotion(6, 2, 4, -4);
print("Inferred emotion from happy face:");
viz(happyFaceEmotion);

// Example: observe a sad-looking face (negative mouth angle, furrowed brows)
var sadFaceEmotion = inferEmotion(-6, 2, -4, 4);
print("Inferred emotion from sad face:");
viz(sadFaceEmotion);

// Example: observe a neutral face
var neutralFaceEmotion = inferEmotion(0, 0, 0, 0);
print("Inferred emotion from neutral face:");
viz(neutralFaceEmotion);
